import React, { useContext, useState, useEffect } from 'react';
import { AuthContext } from '../contexts/AuthContext';

export default function WalletModal({ onClose }) {
  const { user, authFetch, refreshUser } = useContext(AuthContext);
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(true);
  const [addAmount, setAddAmount] = useState('');
  const [adding, setAdding] = useState(false);
  const [message, setMessage] = useState('');
  const [activeTab, setActiveTab] = useState('balance');

  useEffect(() => {
    loadWallet();
  }, []);

  const loadWallet = async () => {
    try {
      setLoading(true);
      const data = await authFetch('/wallet');
      setTransactions(data.transactions || []);
    } catch (err) {
      console.error('Failed to load wallet', err);
    } finally {
      setLoading(false);
    }
  };

  const handleAddMoney = async (amount) => {
    const value = amount || Number(addAmount);
    if (!value || value <= 0) return;

    try {
      setAdding(true);
      setMessage('');
      await authFetch('/wallet/add-money', {
        method: 'POST',
        body: JSON.stringify({ amount: value }),
      });
      await refreshUser();
      await loadWallet();
      setAddAmount('');
      setMessage(`₹${value} added successfully!`);
      setTimeout(() => setMessage(''), 3000);
    } catch (err) {
      setMessage(err.message || 'Failed to add money');
    } finally {
      setAdding(false);
    }
  };

  const presetAmounts = [100, 250, 500, 1000];

  return (
    <div className="modal-overlay" onClick={onClose}>
      <div className="modal-content max-w-lg" onClick={(e) => e.stopPropagation()}>
        {/* Header */}
        <div className="p-5 border-b border-navy-700/50 bg-gradient-to-r from-gold-500/10 to-transparent">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-10 h-10 rounded-xl bg-gradient-to-br from-gold-400 to-gold-600 flex items-center justify-center shadow-lg shadow-gold-500/20">
                <span className="text-navy-900 text-lg font-bold">₹</span>
              </div>
              <div>
                <h2 className="text-lg font-bold text-white">My Wallet</h2>
                <p className="text-xs text-slate-400">Manage your balance</p>
              </div>
            </div>
            <button
              onClick={onClose}
              className="w-8 h-8 rounded-lg bg-navy-700/50 flex items-center justify-center text-slate-400 hover:text-white hover:bg-navy-600 transition-all"
            >
              ✕
            </button>
          </div>
        </div>

        {/* Balance Display */}
        <div className="p-5">
          <div className="bg-gradient-to-br from-navy-900 to-navy-800 rounded-2xl p-6 border border-navy-700/50 mb-5 relative overflow-hidden">
            <div className="absolute top-0 right-0 w-32 h-32 bg-gold-500/5 rounded-full -translate-y-1/2 translate-x-1/2" />
            <p className="text-sm text-slate-400 mb-1">Available Balance</p>
            <p className="text-4xl font-black text-white mb-1">
              ₹{(user?.wallet || 0).toLocaleString()}
            </p>
            <p className="text-xs text-emerald-400">● Active</p>
          </div>

          {/* Tabs */}
          <div className="flex gap-1 bg-navy-900/50 rounded-xl p-1 mb-5">
            {['balance', 'history'].map((tab) => (
              <button
                key={tab}
                onClick={() => setActiveTab(tab)}
                className={`flex-1 py-2 px-3 rounded-lg text-sm font-medium transition-all ${
                  activeTab === tab
                    ? 'bg-gold-500/15 text-gold-400 shadow-sm'
                    : 'text-slate-400 hover:text-white'
                }`}
              >
                {tab === 'balance' ? '💰 Add Money' : '📋 History'}
              </button>
            ))}
          </div>

          {activeTab === 'balance' ? (
            <div className="space-y-4">
              {/* Preset Amounts */}
              <div className="grid grid-cols-4 gap-2">
                {presetAmounts.map((amt) => (
                  <button
                    key={amt}
                    onClick={() => handleAddMoney(amt)}
                    disabled={adding}
                    className="py-3 rounded-xl border border-navy-700/50 text-sm font-semibold text-white hover:border-gold-500/50 hover:bg-gold-500/5 transition-all disabled:opacity-50"
                  >
                    ₹{amt}
                  </button>
                ))}
              </div>

              {/* Custom Amount */}
              <div className="flex gap-2">
                <input
                  type="number"
                  value={addAmount}
                  onChange={(e) => setAddAmount(e.target.value)}
                  placeholder="Custom amount"
                  className="input-field flex-1"
                  min="1"
                />
                <button
                  onClick={() => handleAddMoney()}
                  disabled={adding || !addAmount}
                  className="btn-primary whitespace-nowrap"
                >
                  {adding ? (
                    <span className="flex items-center gap-2">
                      <svg className="animate-spin w-4 h-4" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                      </svg>
                      Adding...
                    </span>
                  ) : (
                    'Add ₹'
                  )}
                </button>
              </div>

              {message && (
                <p className={`text-sm font-medium ${message.includes('success') ? 'text-emerald-400' : 'text-red-400'}`}>
                  {message}
                </p>
              )}

              {/* Razorpay notice */}
              <div className="p-3 rounded-xl bg-sky-500/5 border border-sky-500/10">
                <p className="text-xs text-sky-400">
                  💳 Razorpay integration ready. Configure your API keys in the backend .env file to enable UPI/Card payments.
                </p>
              </div>
            </div>
          ) : (
            <div className="space-y-2 max-h-80 overflow-y-auto pr-1">
              {loading ? (
                <div className="text-center py-8">
                  <div className="animate-spin w-8 h-8 mx-auto border-2 border-gold-500 border-t-transparent rounded-full" />
                </div>
              ) : transactions.length === 0 ? (
                <div className="text-center py-8 text-slate-500">
                  <p className="text-3xl mb-2">📭</p>
                  <p className="text-sm">No transactions yet</p>
                </div>
              ) : (
                transactions.map((tx, i) => (
                  <div
                    key={tx._id || i}
                    className="flex items-center justify-between p-3 rounded-xl bg-navy-900/50 border border-navy-700/30 hover:border-navy-600/50 transition-all"
                  >
                    <div className="flex items-center gap-3">
                      <div
                        className={`w-8 h-8 rounded-lg flex items-center justify-center text-sm ${
                          tx.type === 'credit'
                            ? 'bg-emerald-500/15 text-emerald-400'
                            : 'bg-red-500/15 text-red-400'
                        }`}
                      >
                        {tx.type === 'credit' ? '↓' : '↑'}
                      </div>
                      <div>
                        <p className="text-sm font-medium text-white capitalize">
                          {tx.reason || tx.type}
                        </p>
                        <p className="text-xs text-slate-500">
                          {new Date(tx.createdAt).toLocaleDateString('en-IN', {
                            day: 'numeric',
                            month: 'short',
                            hour: '2-digit',
                            minute: '2-digit',
                          })}
                        </p>
                      </div>
                    </div>
                    <span
                      className={`font-bold text-sm ${
                        tx.type === 'credit' ? 'text-emerald-400' : 'text-red-400'
                      }`}
                    >
                      {tx.type === 'credit' ? '+' : '-'}₹{tx.amount}
                    </span>
                  </div>
                ))
              )}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
